import{_ as t,o as a,c as o,ag as s}from"./chunks/framework.Lq6hU67C.js";const g=JSON.parse('{"title":"Demo scene","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/demo-scene.md","filePath":"how-to/demo-scene.md"}'),n={name:"how-to/demo-scene.md"};function d(r,e,i,l,c,h){return a(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="demo-scene" tabindex="-1">Demo scene <a class="header-anchor" href="#demo-scene" aria-label="Permalink to &quot;Demo scene&quot;">​</a></h1><p>The demo scene is the fastest way to validate Live Leaks, scene transitions, and ILPP-instrumented call sites.</p><h2 id="create-the-demo" tabindex="-1">Create the demo <a class="header-anchor" href="#create-the-demo" aria-label="Permalink to &quot;Create the demo&quot;">​</a></h2><p>Menu: <strong>Tools → Addressables Leak Detector → Create Demo Scene</strong></p><p>This:</p><ul><li>Creates or refreshes <code>DemoLeakScene</code> and <code>DemoLeakScene_B</code></li><li>Registers Addressables entries <code>demo_asset</code> and <code>demo_scene_b</code></li><li>Enables <code>DemoLeakScene</code> in Build Settings (Play entry)</li><li>Keeps <code>DemoLeakScene_B</code> <strong>addressable only</strong> (disabled in Build Settings — Unity rule for addressable scenes)</li><li>Sets Addressables Play Mode to <strong>Use Asset Database (fastest)</strong></li></ul><h2 id="play-workflow" tabindex="-1">Play workflow <a class="header-anchor" href="#play-workflow" aria-label="Permalink to &quot;Play workflow&quot;">​</a></h2><ol><li>Open <code>DemoLeakScene</code></li><li>Enter Play Mode</li><li>Use <strong>Window → Addressables Leak Detector</strong> alongside the Game view</li><li>Click demo buttons and observe Live Leaks</li></ol><h2 id="basic-scenarios-manual-tracking-in-demo-assembly" tabindex="-1">Basic scenarios (manual tracking in demo assembly) <a class="header-anchor" href="#basic-scenarios-manual-tracking-in-demo-assembly" aria-label="Permalink to &quot;Basic scenarios (manual tracking in demo assembly)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Button</th><th>Expected Live Leaks result</th></tr></thead><tbody><tr><td><strong>Create Leak</strong></td><td>Live handle, origin <code>LeakDemoController.cs</code></td></tr><tr><td><strong>Load + Release</strong></td><td>No live handle after release</td></tr><tr><td><strong>Instantiate Leak</strong></td><td>Live instantiate handle</td></tr><tr><td><strong>Instantiate + ReleaseInstance</strong></td><td>No live handle after release</td></tr><tr><td><strong>Leak + Scene B (Single)</strong></td><td>Handle stays live, turns <strong>red</strong> (<code>SceneSurvivor</code>) after non-additive transition</td></tr><tr><td><strong>Leak + Scene B (Additive)</strong></td><td>Handle stays live, stays grey/yellow (not red)</td></tr><tr><td><strong>Release + Scene B</strong></td><td>No live handle after transition</td></tr></tbody></table><h2 id="ilpp-instrumented-scenarios" tabindex="-1">ILPP instrumented scenarios <a class="header-anchor" href="#ilpp-instrumented-scenarios" aria-label="Permalink to &quot;ILPP instrumented scenarios&quot;">​</a></h2><p>These buttons call <code>AddressablesInstrumentationSamples</code> — origin file must be <code>AddressablesInstrumentationSamples.cs</code>.</p><table tabindex="0"><thead><tr><th>Button</th><th>Expected result</th></tr></thead><tbody><tr><td><strong>AssetRef Leak</strong></td><td>Live handle via <code>AssetReference.LoadAssetAsync</code></td></tr><tr><td><strong>AssetRef + ReleaseAsset</strong></td><td>No live handle after <code>ReleaseAsset</code></td></tr><tr><td><strong>Addressable Scene Leak</strong></td><td>Live handle, <code>LoadScene</code> operation kind</td></tr><tr><td><strong>Scene Load + Unload</strong></td><td>No live handle after <code>UnloadSceneAsync</code></td></tr></tbody></table><h2 id="scene-b-navigation" tabindex="-1">Scene B navigation <a class="header-anchor" href="#scene-b-navigation" aria-label="Permalink to &quot;Scene B navigation&quot;">​</a></h2><ul><li><strong>Leak + Scene B</strong> loads Scene B via <code>Addressables.LoadSceneAsync(&quot;demo_scene_b&quot;)</code>.</li><li><strong>Back to Main Scene</strong> releases surviving demo handles, then returns to <code>DemoLeakScene</code>.</li></ul><h2 id="acceptance-checklist" tabindex="-1">Acceptance checklist <a class="header-anchor" href="#acceptance-checklist" aria-label="Permalink to &quot;Acceptance checklist&quot;">​</a></h2><ul><li>Non-additive without release → red <code>SceneSurvivor</code> with correct leak trace.</li><li>Additive without release → not red.</li><li>Release before non-additive transition → no live entry.</li><li>Repeated non-additive leaks group by call site (<code>×N</code>).</li><li>ILPP AssetRef leak → origin <code>AddressablesInstrumentationSamples.cs</code>.</li><li>ILPP healthy unload → no live entry after release.</li><li>Exiting Play Mode clears registry state.</li></ul><h2 id="demo-overlay" tabindex="-1">Demo overlay <a class="header-anchor" href="#demo-overlay" aria-label="Permalink to &quot;Demo overlay&quot;">​</a></h2><p>If <strong>Demo content not configured</strong> appears, re-run <strong>Create Demo Scene</strong> and confirm Addressables groups contain <code>demo_asset</code>.</p>',19)])])}const u=t(n,[["render",d]]);export{g as __pageData,u as default};
